 {"id":"asupersync-ed9","title":"Implement error types and error handling strategy","description":"## Purpose
Define the error type hierarchy for Asupersync. Proper error handling is critical for debugging, user experience, and maintaining the correctness guarantees.

## Design Principles

1. **Errors are informative**: Include context for debugging
2. **Errors are typed**: Different error kinds for different scenarios
3. **Errors compose**: Can wrap underlying errors
4. **No panics in library code**: All errors are returned, not thrown

## Core Error Type

```rust
/// The main error type for Asupersync operations
#[derive(Debug)]
pub struct Error {
    kind: ErrorKind,
    context: Option<String>,
    source: Option<Box<dyn std::error::Error + Send + Sync>>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ErrorKind {
    // === Cancellation ===
    /// Operation was cancelled
    Cancelled,
    /// Cancellation timeout exceeded
    CancelTimeout,

    // === Budget ===
    /// Deadline exceeded
    DeadlineExceeded,
    /// Poll quota exhausted
    PollQuotaExhausted,
    /// Cost quota exhausted
    CostQuotaExhausted,

    // === Channel ===
    /// Channel is closed/disconnected
    ChannelClosed,
    /// Channel is full (would block)
    ChannelFull,
    /// Channel is empty (would block)
    ChannelEmpty,

    // === Obligation ===
    /// Obligation was not resolved before region close
    ObligationLeak,
    /// Tried to resolve already-resolved obligation
    ObligationAlreadyResolved,

    // === Region ===
    /// Region is already closed
    RegionClosed,
    /// Task not owned by region
    TaskNotOwned,

    // === Internal ===
    /// Internal runtime error (bug)
    Internal,
    /// Invalid state transition
    InvalidStateTransition,

    // === User ===
    /// User-provided error
    User,
}

impl Error {
    pub fn new(kind: ErrorKind) -> Self {
        Self { kind, context: None, source: None }
    }

    pub fn with_context(mut self, ctx: impl Into<String>) -> Self {
        self.context = Some(ctx.into());
        self
    }

    pub fn with_source(mut self, source: impl std::error::Error + Send + Sync + 'static) -> Self {
        self.source = Some(Box::new(source));
        self
    }

    pub fn kind(&self) -> ErrorKind {
        self.kind
    }

    pub fn is_cancelled(&self) -> bool {
        self.kind == ErrorKind::Cancelled
    }

    pub fn is_timeout(&self) -> bool {
        matches!(self.kind, ErrorKind::DeadlineExceeded | ErrorKind::CancelTimeout)
    }
}

impl std::fmt::Display for Error {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{:?}", self.kind)?;
        if let Some(ctx) = &self.context {
            write!(f, ": {}", ctx)?;
        }
        Ok(())
    }
}

impl std::error::Error for Error {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        self.source.as_ref().map(|e| e.as_ref() as _)
    }
}
```

