## Channel-Specific Errors

```rust
/// Error when sending on a channel
#[derive(Debug)]
pub enum SendError<T> {
    /// Channel receiver was dropped
    Disconnected(T),
    /// Would block (for try_send)
    Full(T),
}

/// Error when receiving from a channel
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RecvError {
    /// Channel sender was dropped
    Disconnected,
    /// Would block (for try_recv)
    Empty,
}

/// Error when acquiring a semaphore permit
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AcquireError {
    /// Semaphore was closed
    Closed,
}
```

## Converting Between Error Types

```rust
impl From<RecvError> for Error {
    fn from(e: RecvError) -> Self {
        match e {
            RecvError::Disconnected => Error::new(ErrorKind::ChannelClosed),
            RecvError::Empty => Error::new(ErrorKind::ChannelEmpty),
        }
    }
}

impl<T> From<SendError<T>> for Error {
    fn from(e: SendError<T>) -> Self {
        match e {
            SendError::Disconnected(_) => Error::new(ErrorKind::ChannelClosed),
            SendError::Full(_) => Error::new(ErrorKind::ChannelFull),
        }
    }
}
```

## Cancelled as Error

```rust
/// Marker type for cancellation
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Cancelled {
    pub reason: CancelReason,
}

impl From<Cancelled> for Error {
    fn from(c: Cancelled) -> Self {
        Error::new(ErrorKind::Cancelled)
            .with_context(format!("{:?}", c.reason))
    }
}
```

## Error Context Helpers

```rust
/// Extension trait for adding context to Results
pub trait ResultExt<T> {
    fn context(self, ctx: impl Into<String>) -> Result<T>;
    fn with_context<F: FnOnce() -> String>(self, f: F) -> Result<T>;
}

impl<T, E: Into<Error>> ResultExt<T> for std::result::Result<T, E> {
    fn context(self, ctx: impl Into<String>) -> Result<T> {
        self.map_err(|e| e.into().with_context(ctx))
    }

    fn with_context<F: FnOnce() -> String>(self, f: F) -> Result<T> {
        self.map_err(|e| e.into().with_context(f()))
    }
}
