## Invariant Violations (for debugging)

```rust
/// Invariant violation detected during testing
#[derive(Debug)]
pub struct InvariantViolation {
    pub invariant: Invariant,
    pub description: String,
    pub evidence: Vec<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Invariant {
    TreeOwnership,       // INV-TREE
    TaskOwned,           // INV-TASK-OWNED
    Quiescence,          // INV-QUIESCENCE
    CancelPropagates,    // INV-CANCEL-PROPAGATES
    ObligationBounded,   // INV-OBLIGATION-BOUNDED
    ObligationLinear,    // INV-OBLIGATION-LINEAR
    MaskBounded,         // INV-MASK-BOUNDED
    DeadlineMonotone,    // INV-DEADLINE-MONOTONE
    LoserDrained,        // INV-LOSER-DRAINED
}

impl InvariantViolation {
    pub fn new(invariant: Invariant, desc: impl Into<String>) -> Self {
        Self {
            invariant,
            description: desc.into(),
            evidence: Vec::new(),
        }
    }

    pub fn with_evidence(mut self, ev: impl Into<String>) -> Self {
        self.evidence.push(ev.into());
        self
    }
}
