#[cfg(test)]
mod context_tests {
    // Creation
    #[test] fn test_context_creation() {
        let ctx = SecurityContext::for_testing(42);
        assert_eq!(ctx.mode(), AuthMode::Strict);
        assert_eq!(ctx.stats().symbols_signed, 0);
    }

    // Sign and verify
    #[test] fn test_sign_and_verify() {
