        let symbol = make_symbol(&[1, 2, 3]);
        let auth = AuthenticatedSymbol::from_parts(symbol, AuthenticationTag::zero());
        let result = ctx.verify_authenticated_symbol(&auth);
        assert!(result.is_ok()); // Doesn't fail
