mod property_tests {
    use proptest::prelude::*;

    proptest! {
        #[test]
        fn prop_tag_verification_correct(
            seed in 0u64..1000,
            data in prop::collection::vec(any::<u8>(), 0..1000)
        ) {
            let key = AuthKey::from_seed(seed);
            let symbol = Symbol::new_for_test(1, 0, 0, &data);
            let tag = AuthenticationTag::compute(&key, &symbol);
            prop_assert!(tag.verify(&key, &symbol));
        }

        #[test]
        fn prop_tag_fails_on_tampering(
            seed in 0u64..1000,
            data in prop::collection::vec(any::<u8>(), 1..100),
            tamper_idx in 0usize..100
        ) {
            let key = AuthKey::from_seed(seed);
            let symbol = Symbol::new_for_test(1, 0, 0, &data);
            let tag = AuthenticationTag::compute(&key, &symbol);

            let mut tampered_data = data.clone();
            let idx = tamper_idx % tampered_data.len();
            tampered_data[idx] = tampered_data[idx].wrapping_add(1);
            let tampered = Symbol::new_for_test(1, 0, 0, &tampered_data);

            prop_assert!(!tag.verify(&key, &tampered));
        }

        #[test]
        fn prop_different_keys_produce_different_tags(
            seed1 in 0u64..1000,
            seed2 in 0u64..1000,
            data in prop::collection::vec(any::<u8>(), 1..100)
        ) {
            prop_assume!(seed1 != seed2);
            let key1 = AuthKey::from_seed(seed1);
            let key2 = AuthKey::from_seed(seed2);
            let symbol = Symbol::new_for_test(1, 0, 0, &data);
            let tag1 = AuthenticationTag::compute(&key1, &symbol);
            let tag2 = AuthenticationTag::compute(&key2, &symbol);
            prop_assert_ne!(tag1, tag2);
